import React, { useState } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { Menu, X } from 'lucide-react';
import { useAuth } from '../contexts/AuthContext';

const Navbar = () => {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout } = useAuth();

  const navItems = [
    { name: 'Beranda', path: '/' },
    { name: 'Layanan', path: '/layanan' },
    { name: 'Armada', path: '/armada' },
    { name: 'Testimoni', path: '/testimoni' },
    { name: 'Pesanan', path: '/pesanan' },
  ];

  const isActive = (path) => location.pathname === path;

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <nav className="bg-white shadow-sm fixed w-full top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-20">
          {/* Logo */}
          <Link to="/" className="flex items-center">
            <h1 className="text-2xl font-bold text-[#0A2647] tracking-tight">
              MANDIRI PERKASA
            </h1>
          </Link>

          {/* Desktop Navigation */}
          <div className="hidden md:flex items-center space-x-8">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                className={`text-base font-medium transition-colors relative ${
                  isActive(item.path)
                    ? 'text-[#0A2647]'
                    : 'text-gray-600 hover:text-[#0A2647]'
                }`}
                data-testid={`nav-${item.name.toLowerCase()}`}
              >
                {item.name}
                {isActive(item.path) && (
                  <div className="absolute -bottom-6 left-0 right-0 h-0.5 bg-[#D97706]" />
                )}
              </Link>
            ))}
          </div>

          {/* Auth Buttons */}
          <div className="hidden md:flex items-center space-x-4">
            {user ? (
              <div className="flex items-center space-x-4">
                <span className="text-sm text-gray-600">{user.name}</span>
                <button
                  onClick={handleLogout}
                  className="px-4 py-2 text-sm font-medium text-gray-600 hover:text-[#0A2647] transition-colors"
                  data-testid="logout-button"
                >
                  Keluar
                </button>
              </div>
            ) : (
              <>
                <Link
                  to="/masuk"
                  className="px-4 py-2 text-sm font-medium text-gray-600 hover:text-[#0A2647] transition-colors"
                  data-testid="masuk-button"
                >
                  Masuk
                </Link>
                <Link
                  to="/daftar"
                  className="px-6 py-2.5 text-sm font-medium text-white bg-[#0A2647] rounded hover:bg-[#144272] transition-colors"
                  data-testid="daftar-button"
                >
                  Daftar
                </Link>
              </>
            )}
          </div>

          {/* Mobile menu button */}
          <button
            onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
            className="md:hidden p-2"
            data-testid="mobile-menu-button"
          >
            {mobileMenuOpen ? (
              <X className="h-6 w-6 text-gray-600" />
            ) : (
              <Menu className="h-6 w-6 text-gray-600" />
            )}
          </button>
        </div>
      </div>

      {/* Mobile Menu */}
      {mobileMenuOpen && (
        <div className="md:hidden bg-white border-t">
          <div className="px-4 py-4 space-y-3">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                onClick={() => setMobileMenuOpen(false)}
                className={`block py-2 text-base font-medium ${
                  isActive(item.path)
                    ? 'text-[#0A2647]'
                    : 'text-gray-600'
                }`}
              >
                {item.name}
              </Link>
            ))}
            <div className="pt-3 border-t space-y-2">
              {user ? (
                <>
                  <div className="text-sm text-gray-600 py-2">{user.name}</div>
                  <button
                    onClick={() => {
                      handleLogout();
                      setMobileMenuOpen(false);
                    }}
                    className="block w-full text-left py-2 text-base font-medium text-gray-600"
                  >
                    Keluar
                  </button>
                </>
              ) : (
                <>
                  <Link
                    to="/masuk"
                    onClick={() => setMobileMenuOpen(false)}
                    className="block py-2 text-base font-medium text-gray-600"
                  >
                    Masuk
                  </Link>
                  <Link
                    to="/daftar"
                    onClick={() => setMobileMenuOpen(false)}
                    className="block py-2 text-base font-medium text-[#0A2647]"
                  >
                    Daftar
                  </Link>
                </>
              )}
            </div>
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
